import threading
import time
from my_lru_cache import LRUCache

def test_deadlock_risk():
    cache = LRUCache(max_size=1000, ttl=60)

    def worker_read(key):
        for _ in range(1000):
            cache.get(key)

    def worker_write(key):
        for _ in range(1000):
            cache.set(key, f"value_{_}")

    threads = []
    for i in range(50):
        t1 = threading.Thread(target=worker_read, args=(f"key_{i}",))
        t2 = threading.Thread(target=worker_write, args=(f"key_{i}",))
        threads.append(t1)
        threads.append(t2)
        t1.start()
        t2.start()

    for t in threads:
        t.join(timeout=5)

    # Vérification de l'absence de deadlock
    assert all(not t.is_alive() for t in threads), "Deadlock détecté"

